[profile.release]
# debug = true

[workspace]
resolver = "2"
members = [
    # 普通模块
    "crates/devices",
    "crates/executor",
    "crates/runtime",
    "crates/signal",
    "crates/sync",

    # 文件系统
    "filesystem/devfs",
    "filesystem/fs",
    "filesystem/procfs",
    "filesystem/ramfs",
    "filesystem/vfscore",

    # 驱动
    "driver/general-plic",
    "driver/kgoldfish-rtc",
    "driver/kramdisk",
    "driver/kvirtio",
    "driver/ns16550a",

    #内核
    "kernel",
]

[workspace.dependencies]
fs = { path = "filesystem/fs" }
devfs = { path = "filesystem/devfs" }
procfs = { path = "filesystem/procfs" }
vfscore = { path = "filesystem/vfscore" }
ramfs = { path = "filesystem/ramfs" }

general-plic = { path = "driver/general-plic" }
kgoldfish-rtc = { path = "driver/kgoldfish-rtc" }
kramdisk = { path = "driver/kramdisk" }
kvirtio = { path = "driver/kvirtio" }
ns16550a = { path = "driver/ns16550a" }

devices = { path = "crates/devices" }
executor = { path = "crates/executor" }
runtime = { path = "crates/runtime" }
logging = { path = "crates/logging" }
signal = { path = "crates/signal" }
sync = { path = "crates/sync" }

polyhal = { version = "0.2.4", features = ["logger", "trap"] }
polyhal-boot = { version = "0.2.4" }
polyhal-trap = { version = "0.2.4" }
fdt-parser = { version = "0.4.12" }

syscalls = { git = "https://github.com/jasonwhite/syscalls.git", default-features = false }

[patch.crates-io]
# polyhal = { path = "../polyhal/polyhal" }
# polyhal-boot = { path = "../polyhal/polyhal-boot" }
# polyhal-trap = { path = "../polyhal/polyhal-trap" }

SHELL := /bin/bash
export ROOT_MANIFEST_DIR := $(shell pwd)
RELEASE := release
LOG ?= error
# RISC-V 配置
RISCV_TARGET := riscv64gc-unknown-none-elf
RISCV_ARCH := riscv64
RISCV_KERNEL_ELF := target/$(RISCV_TARGET)/$(RELEASE)/kernel
RISCV_KERNEL_OUT := kernel-rv
RISCV_FEATURES :=   # 根据需要调整，例如启用 virtio 驱动

# LoongArch 配置
LOONGARCH_TARGET := loongarch64-unknown-none
LOONGARCH_ARCH := loongarch64
LOONGARCH_KERNEL_ELF := target/$(LOONGARCH_TARGET)/$(RELEASE)/kernel
LOONGARCH_KERNEL_OUT := kernel-la
LOONGARCH_FEATURES :=   # 根据需要调整

.PHONY: all build-riscv build-loongarch clean

all: build-riscv build-loongarch

build-riscv:
	@echo "Building RISC-V kernel..."
	@if [ -d dotcargo ]; then mv dotcargo .cargo; fi
	@BOARD=qemu LOG=$(LOG) RUSTFLAGS="-Clink-arg=-no-pie --cfg=driver=\"kvirtio\" --cfg=board=\"qemu\" --cfg=root_fs=\"ext4\"" \
	cargo build --target $(RISCV_TARGET) --features "$(RISCV_FEATURES)" --release --offline || exit 1
	@rust-objcopy --binary-architecture=riscv64 -O binary  $(RISCV_KERNEL_ELF) $(RISCV_KERNEL_OUT)
	@if [ -d .cargo ]; then mv .cargo dotcargo; fi

build-loongarch:
	@echo "Building LoongArch kernel..."
	@if [ -d dotcargo ]; then mv dotcargo .cargo; fi
	@BOARD=qemu LOG=$(LOG) RUSTFLAGS="-Clink-arg=-no-pie --cfg=driver=\"kvirtio\" --cfg=board=\"qemu\" --cfg=root_fs=\"ext4\"" \
	cargo build --target $(LOONGARCH_TARGET) --features "$(LOONGARCH_FEATURES)" --release --offline || exit 1
	@cp $(LOONGARCH_KERNEL_ELF) $(LOONGARCH_KERNEL_OUT) || exit 1
	@if [ -d .cargo ]; then mv .cargo dotcargo; fi


clean:
	@rm -rf target/ kernel-rv kernel-la

