/// 用户态动态链接用户程序的偏移
pub const USER_DYN_ADDR: usize = 0x20000000;

/// 用户态栈顶
pub const USER_STACK_TOP: usize = 0x8000_0000;

/// 用户栈初始大小
pub const USER_STACK_INIT_SIZE: usize = 0x20000;

// use backtrace::backtrace;
use core::panic::PanicInfo;

use polyhal::instruction::shutdown;

#[inline]
fn hart_id() -> usize {
    0
}

// 程序遇到错误
#[panic_handler]
fn panic_handler(info: &PanicInfo) -> ! {
    if let Some(location) = info.location() {
        println!(
            "\x1b[1;31m[Core {}] [{}:{}]\x1b[0m",
            hart_id(),
            location.file(),
            location.line(),
        );
    }
    println!(
        "\x1b[1;31m[Core {}] panic: '{}'\x1b[0m",
        hart_id(),
        info.message()
    );
    // backtrace();
    println!("!TEST FINISH!");
    // loop {}

    shutdown();
}

