        debug!("sys_chdir @ path: {}", path);
        let new_dir = self.task.fd_open(AT_CWD, path, OpenFlags::O_RDONLY)?;
        match new_dir.file_type()? {
            fs::FileType::Directory => {
                self.task.pcb.lock().curr_dir = Arc::new(new_dir);
                Ok(0)
            }
            _ => Err(Errno::ENOTDIR),
        }
