#### 3.5.6 管道（Pipe）

```rust
pub fn create_pipe() -> (Arc<Pipe>, Arc<Pipe>) {
    let buffer = Arc::new(Mutex::new(VecDeque::new()));
    let read_end = Arc::new(Pipe { buffer: buffer.clone(), is_read: true });
    let write_end = Arc::new(Pipe { buffer, is_read: false });
